formula.beforeSaveScript:
$stage = entity\attribute('stage');

ifThen(
    $stage == 'Discovery',
    entity\setAttribute('probability', 10)
);
ifThen(
    $stage == 'Quoting',
    entity\setAttribute('probability', 30)
);
ifThen(
    $stage == 'Markets Out / Shopping',
    entity\setAttribute('probability', 45)
);
ifThen(
    $stage == 'Proposal Presented',
    entity\setAttribute('probability', 60)
);
ifThen(
    $stage == 'Negotiation',
    entity\setAttribute('probability', 80)
);
ifThen(
    $stage == 'Closed Won',
    entity\setAttribute('probability', 100)
);
ifThen(
    $stage == 'Closed Lost',
    entity\setAttribute('probability', 0)
);

$estPremium = entity\attribute('estimatedPremium');
ifThen(
    $estPremium != null,
    entity\setAttribute('amount', $estPremium)
);
ifThen(
    $estPremium == null,
    entity\setAttribute('amount', 0)
);

$estCurrency = entity\attribute('estimatedPremiumCurrency');
ifThen(
    $estCurrency != null,
    entity\setAttribute('amountCurrency', $estCurrency)
);
ifThen(
    $estCurrency == null,
    entity\setAttribute('amountCurrency', 'USD')
);

ifThen(
    isEmpty(entity\attribute('name')),
    ifElse(
        !isEmpty(entity\attribute('accountName')) && !isEmpty(entity\attribute('lineOfBusiness')),
        entity\setAttribute('name', string\concatenate(entity\attribute('accountName'), ' - ', entity\attribute('lineOfBusiness'), ' - ', datetime\today())),
        ifElse(
            !isEmpty(entity\attribute('accountName')),
            entity\setAttribute('name', string\concatenate(entity\attribute('accountName'), ' - ', datetime\today())),
            entity\setAttribute('name', string\concatenate('Opportunity - ', datetime\today()))
        )
    )
);

$premium_amount = entity\attribute('premium_amount');
ifThen(
    $premium_amount == null,
    $premium_amount = 0
);

$commission_rate = entity\attribute('commission_rate');
ifThen(
    $commission_rate == null,
    $commission_rate = 0.10
);
ifThen(
    $commission_rate == '',
    $commission_rate = 0.10
);
ifThen(
    $commission_rate > 1,
    $commission_rate = $commission_rate / 100
);

entity\setAttribute(
    'commissionAmount',
    number\round($premium_amount * $commission_rate, 2)
);

$status = entity\attribute('status');
$premiumAtRiskCalc = 0;
ifThen(
    $status == 'Active',
    $premiumAtRiskCalc = $premium_amount
);
ifThen(
    $status == 'Up for Renewal',
    $premiumAtRiskCalc = $premium_amount
);
ifThen(
    $status == 'Renewing',
    $premiumAtRiskCalc = $premium_amount
);
ifThen(
    $status == 'Renewed',
    $premiumAtRiskCalc = $premium_amount
);

entity\setAttribute('premiumAtRisk', $premiumAtRiskCalc);
